return items.map(item => {
  let data = item.json;

  // ถ้า AI ส่งมาเป็น string ให้ parse
  if (typeof data === "string") {
    data = JSON.parse(data);
  }

  // ถ้าอยู่ใน key ชื่อ output
  if (typeof data.output === "string") {
    data = JSON.parse(data.output);
  }

  return {
    json: data
  };
});

const text = ($json.message?.text || '').toLowerCase().trim();

let mode = "unknown";

// ตรวจ TT number
if (/tt\d+/i.test(text)) {
  if (text.includes("เช็ค") || text.includes("check")) {
    mode = "query_ticket";
  } else {
    mode = "update_ticket";
  }
}

// สรุปวันนี้
else if (text.includes("วันนี้")) {
  mode = "today_summary";
}

// query site
else if (text.includes("site")) {
  mode = "query_site";
}

// คืนค่าแบบ merge กับ input เดิม (สำคัญมากสำหรับ production)
return {
  ...$json,
  text,
  mode,
  replyToken: $json.replyToken,
  userId: $json.source?.userId
};

function safeParse(raw) {
  if (!raw) return null;

  // ถ้าเป็น object อยู่แล้ว
  if (typeof raw === "object") return raw;

  if (typeof raw !== "string") return null;

  try {
    const cleaned = raw
      .replace(/^```json\s*/i, '')
      .replace(/```$/i, '')
      .trim();

    return JSON.parse(cleaned);
  } catch (e) {
    return null;
  }
}

const original = $json; // ✅ เก็บข้อมูลเดิมทั้งหมด (userId, replyToken ฯลฯ)
const parsed = safeParse(original.finalMessage);

const requiredKeys = [
  "ticket_no",
  "severity",
  "fault_date",
  "expected_date",
  "owner",
  "go_time",
  "start_time",
  "done_time",
  "status"
];

// ❌ กรณี AI ส่ง JSON ไม่ถูก
if (!parsed) {
  return [{
    json: {
      ...original,
      error: true,
      message: "❌ AI ส่ง JSON ไม่ถูกต้อง"
    }
  }];
}

// ❌ กรณี key ไม่ครบ
for (const key of requiredKeys) {
  if (!(key in parsed)) {
    return [{
      json: {
        ...original,
        error: true,
        message: `❌ JSON structure ไม่ครบ (ขาด ${key})`
      }
    }];
  }
}

// ✅ สำเร็จ → merge ของเดิม + parsed
return [{
  json: {
    ...original,  // ✅ เก็บ userId / replyToken / source
    ...parsed     // ✅ ทับด้วยข้อมูลที่ parse แล้ว
  }
}];

