// ===============================
// Helper Functions
// ===============================
const clean = (v) => {
  if (v === undefined || v === null) return null;
  const s = String(v).trim();
  return s === "" ? null : s;
};

const formatDateTime = (d) => {
  if (!d) return null;

  let date = new Date(d);

  if (isNaN(date)) {
    const parts = String(d).split(/[\/ :]/);
    if (parts.length >= 3) {
      const [day, month, year, h = 0, m = 0, s = 0] = parts;
      date = new Date(year, month - 1, day, h, m, s);
    }
  }

  if (isNaN(date)) return null;

  const pad = (n) => n.toString().padStart(2, "0");

  return (
    date.getFullYear() +
    "-" +
    pad(date.getMonth() + 1) +
    "-" +
    pad(date.getDate()) +
    " " +
    pad(date.getHours()) +
    ":" +
    pad(date.getMinutes()) +
    ":" +
    pad(date.getSeconds())
  );
};

// ===============================
// Get Raw Input
// ===============================
const data = $json;

// ===============================
// Field Mapping
// ===============================
const ticketNo = clean(
  data["TT No"] ??
  data["TTNo"] ??
  data.ticket_no ??
  data.ticketNo ??
  data.id
);

if (!ticketNo) {
  return [{
    json: {
      success: false,
      error: "TT No missing"
    }
  }];
}

const severityRaw = clean(data.Severity ?? data.severity);
const severity = severityRaw ? severityRaw.toUpperCase() : null;

// Open Ticket
const openTicketRaw =
  data.OpenTicketDate ??
  data.open_ticket_date;

const openTicket = formatDateTime(openTicketRaw);

// Fault Date
const faultDateRaw =
  data.fault_date ??
  openTicketRaw;

const faultDate = formatDateTime(faultDateRaw);

// Expected
let expectedDateRaw =
  data.ExpectedDate ??
  data.expected_date;

let expectedDate = formatDateTime(expectedDateRaw);

// Other fields
const owner = clean(data.owner ?? data.Owner);
const goTime = clean(data.go_time ?? data.GoTime);
const startTime = clean(data.start_time ?? data.StartTime);
const doneTime = clean(data.done_time ?? data.DoneTime);

// ===============================
// Auto Calculate Expected Date
// ===============================
if (!expectedDate && faultDate && severity) {

  const base = new Date(faultDate);

  const addDays = (days) => {
    const d = new Date(base);
    d.setDate(d.getDate() + days);
    return formatDateTime(d);
  };

  switch (severity) {
    case "CRITICAL":
    case "NSA4":
      expectedDate = addDays(1);
      break;

    case "HIGH":
    case "NSA3":
      expectedDate = addDays(3);
      break;

    case "MEDIUM":
    case "NSA2":
      expectedDate = addDays(5);
      break;

    case "LOW":
    case "NSA1":
      expectedDate = addDays(7);
      break;
  }
}

// ===============================
// Auto Status
// ===============================
let status = "OPEN";

if (doneTime) {
  status = "DONE";
} else if (startTime) {
  status = "IN PROGRESS";
}

// ===============================
// Final Output
// ===============================
return {
  success: true,
  ticket_no: ticketNo,
  severity: severity,
  open_ticket: openTicket,
  fault_date: faultDate,
  expected_date: expectedDate,
  owner: owner,
  go_time: goTime,
  start_time: startTime,
  done_time: doneTime,
  status
};

return items.map(item => {
  if (!item.json.reply || item.json.reply.trim() === "") {
    item.json.reply = "ขออภัย ระบบไม่สามารถสร้างคำตอบได้ กรุณาลองใหม่อีกครั้ง";
  }
  return item;
});

